
(async () => {
  try {
    const b64 = "";
    const byteChars = atob(b64);
    const byteNumbers = new Array(byteChars.length);
    for (let i = 0; i < byteChars.length; i++) {
      byteNumbers[i] = byteChars.charCodeAt(i);
    }
    const byteArray = new Uint8Array(byteNumbers);
    const blob = new Blob([byteArray], { type: 'video/mp4' });
    const file = new File([blob], 'day-003-recap.mp4', { type: 'video/mp4' });
    
    const inputs = document.querySelectorAll('input[type="file"]');
    const fileInput = inputs[inputs.length - 1];
    
    if (!fileInput) return 'No file input found. Inputs: ' + inputs.length;
    
    const dt = new DataTransfer();
    dt.items.add(file);
    fileInput.files = dt.files;
    fileInput.dispatchEvent(new Event('change', { bubbles: true }));
    
    return 'Injected ' + file.name + ' (' + (file.size/1024).toFixed(1) + 'KB) into input[accept=' + fileInput.accept + ']';
  } catch(e) {
    return 'Error: ' + e.message;
  }
})()
